import{_ as a,c as i,o as t,a_ as o}from"./chunks/framework.DJuGJ-7V.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"documents/interview/javascript.md","filePath":"documents/interview/javascript.md","lastUpdated":1742387780000}'),r={name:"documents/interview/javascript.md"};function l(s,e,n,c,p,d){return t(),i("div",null,e[0]||(e[0]=[o('<h2 id="简单介绍下-promise" tabindex="-1">简单介绍下 Promise <a class="header-anchor" href="#简单介绍下-promise" aria-label="Permalink to &quot;简单介绍下 Promise&quot;">​</a></h2><p>promise 是用来处理异步操作的。 它有三种状态 pending、fullfilled、rejected。 它接受一个函数作为参数，这个函数有两个参数，分别为 resolve 和 reject。 resolve 用来处理异步操作成功的情况，reject 则用来处理失败的情况。 执行 resolve，状态就会从 pending 变到 fullfilled，然后走then方法。 执行 reject，状态就变成 rejected，然后走 catch方法。 无论执行 resolve 还是 reject ，都会走 finally 方法。可以解决回调地狱问题</p><h2 id="简单介绍下-async-await-并说下原理" tabindex="-1">简单介绍下 async/await 并说下原理 <a class="header-anchor" href="#简单介绍下-async-await-并说下原理" aria-label="Permalink to &quot;简单介绍下 async/await 并说下原理&quot;">​</a></h2><p>async 用来声明一个异步函数，返回值是一个 promise，无论内部是否有 await；await 用来等待一个 promise 完成，如果 promise 成功，await 返回resolve 值，如果失败，await 则抛出错误，可以通过 try…catch 捕获</p><p><strong>原理：本质上是 generator 和 promise 的结合</strong></p><ul><li>generator 是一个生成器，使用 function* 来定义，通过 yield 暂停函数执行，并返回一个迭代器对象，再通过迭代器对象的 next 方法恢复执行。</li><li>yield 类似 await，不同的地方在于 generator 返回的是一个迭代器对象，async 函数返回的是一个 promise；async/await 会自动处理异步操作的结果，generator 则需要手动调用 next 方法</li></ul><p><strong>扩展</strong></p><ul><li>对比 promise 优势</li></ul><ol><li>避免链式调用，使异步代码看起来更像是同步的</li><li>使用try…catch捕获错误，比.catch更直观</li></ol><ul><li>迭代器（iterator）和生成器（generator）的区别 迭代器是一个对象，需要手动实现 next 方法；生成器是一个函数，通过 yield 自动实现 next 方法，生成器是迭代器的超集</li></ul><h2 id="作用域、作用域链、闭包以及实际应用场景" tabindex="-1">作用域、作用域链、闭包以及实际应用场景 <a class="header-anchor" href="#作用域、作用域链、闭包以及实际应用场景" aria-label="Permalink to &quot;作用域、作用域链、闭包以及实际应用场景&quot;">​</a></h2><p><strong>作用域</strong>：函数和变量的可访问范围，分为全局作用域和局部作用域（函数作用域和块级作用域）</p><p><strong>作用域链</strong>：作用域链是 JavaScript 查找变量的一种机制。当访问一个变量时，JavaScript 会先在当前作用域查找，如果找不到，会逐级向上查找，直到全局作用域。这个查找路径就是作用域链。</p><p><strong>闭包</strong>：闭包是指函数能够访问其词法作用域中的变量，即使函数在其作用域外执行。</p><p><strong>闭包实际应用场景</strong>：</p><ul><li>数据封装和私有变量</li><li>函数柯里化（多参数函数转化为一系列但参数函数）</li><li>事件处理（button.addEventListener）</li><li>延迟执行（函数里有一个settimeout，settimeout中访问了函数参数）</li><li>防抖和节流（防抖通过在内部定义一个timer，然后return一个函数，函数内部先清空上一个timer，然后再给timer重新赋值）</li></ul><h2 id="简单介绍下事件循环" tabindex="-1">简单介绍下事件循环 <a class="header-anchor" href="#简单介绍下事件循环" aria-label="Permalink to &quot;简单介绍下事件循环&quot;">​</a></h2><p>首先，js 是单线程的，运行在浏览器的渲染主线程中。 当浏览器遇到事件处理、定时器、网络请求等操作时，为了不阻塞后续代码的执行，它会将这些异步操作放到一个消息队列中。 等到运行完同步的代码后，浏览器就会看看消息队列里还有没有要执行的任务。 同时，消息队列里的任务分为宏任务和微任务，微任务要比宏任务优先级高。 常见的宏任务有网络请求、定时器、requestAnimationFrame（浏览器中的动画帧回调），常见的微任务有promise.then、await、MutationObserver（DOM 变化的观察者回调），vue 中数据批量更新以及 nexttick 也属于微任务</p><h2 id="如何减少dom操作来防止回流和重绘" tabindex="-1">如何减少dom操作来防止回流和重绘 <a class="header-anchor" href="#如何减少dom操作来防止回流和重绘" aria-label="Permalink to &quot;如何减少dom操作来防止回流和重绘&quot;">​</a></h2><ol><li>将逐个样式修改调整为一次性修改，或者直接添加一个className</li><li>使用css3动画代替js动画</li><li>使用flex布局，相比传统或浮动布局，会少一些布局计算</li><li>减少元素层级嵌套</li><li>使用虚拟dom（通过diff算法批量更新真实dom）</li><li>使用requestAnimationFrame来合并动画帧更新</li></ol><h2 id="cookie、localstorage、sessionstorage-区别" tabindex="-1">cookie、localstorage、sessionstorage 区别 <a class="header-anchor" href="#cookie、localstorage、sessionstorage-区别" aria-label="Permalink to &quot;cookie、localstorage、sessionstorage 区别&quot;">​</a></h2><ol><li><p>存储大小： cookie：约 4KB。 localStorage 和 sessionStorage：约 5MB。</p></li><li><p>生命周期： cookie：可设置过期时间，手动清除或过期后失效。 localStorage：永久存储，除非手动清除。 sessionStorage：页面关闭后自动清除。</p></li><li><p>作用域： cookie：可设置路径和域名，同域名下共享。 localStorage：同域名下共享。 sessionStorage：仅当前页面有效，不共享。</p></li><li><p>与服务器的交互： cookie：每次请求自动携带在 HTTP 头部。 localStorage 和 sessionStorage：不参与服务器通信。</p></li><li><p>应用场景： cookie：存储登录状态、会话信息。 localStorage：长期存储数据，如用户偏好。 sessionStorage：临时存储数据，如表单数据。</p></li></ol><h2 id="通过-json-parse-json-stringfy-实现的深拷贝有什么缺点" tabindex="-1">通过 JSON.parse(JSON.stringfy()) 实现的深拷贝有什么缺点？ <a class="header-anchor" href="#通过-json-parse-json-stringfy-实现的深拷贝有什么缺点" aria-label="Permalink to &quot;通过 JSON.parse(JSON.stringfy()) 实现的深拷贝有什么缺点？&quot;">​</a></h2><ol><li><p>不支持函数： 函数属性会被忽略，拷贝后丢失。</p></li><li><p>不支持特殊对象： RegExp、Map、Set、Date 等对象会被转换为空对象或字符串，无法正确拷贝。</p></li><li><p>不支持循环引用： 如果对象存在循环引用（如 a 引用 b，b 又引用 a），会报错。</p></li><li><p>忽略 undefined 和 Symbol： undefined 和 Symbol 类型的属性会被忽略，拷贝后丢失。</p></li><li><p>性能问题： 对于大对象或复杂结构，JSON.stringify 和 JSON.parse 的性能较差。</p></li></ol>',24)]))}const h=a(r,[["render",l]]);export{g as __pageData,h as default};
